#include <stdlib.h>

int main(void) {
    int *a = malloc(4 * sizeof *a);   /* uninitialized */
    if (!a) return 1;
    int *b = calloc(4, sizeof *b);    /* zeroed */
    if (!b) { free(a); return 1; }
    int *tmp = realloc(a, 8 * sizeof *a);
    if (!tmp) { free(a); free(b); return 1; }
    a = tmp;                           /* safe reassignment */
    free(a);
    free(b);
    return 0;
}

