#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    int x = *(const int*)a, y = *(const int*)b;
    return (x > y) - (x < y);
}

int main(void) {
    int arr[] = {3, 1, 2};
    qsort(arr, 3, sizeof(int), cmp); /* callback via function pointer */
    int (*fp)(const void*, const void*) = cmp;
    printf("%d\n", fp(&arr[0], &arr[1]));
    return 0;
}

