#include <stdio.h>

#define SQUARE(x)  ((x) * (x))    /* parenthesize! */
#define MAX(a, b)  ((a) > (b) ? (a) : (b))

int main(void) {
    printf("%d\n", SQUARE(2 + 3));  /* 25, not 11 */
    int i = 5;
    /* MAX(i++, 4) would increment i twice: side-effect bug */
    printf("%d\n", MAX(i, 4));
    return 0;
}

