#include <stdio.h>

#define READ  (1u << 0)
#define WRITE (1u << 1)

int main(void) {
    unsigned flags = 0;
    flags |= READ | WRITE;     /* set bits */
    if (flags & WRITE) puts("writable");
    flags &= ~WRITE;           /* clear WRITE */
    flags ^= READ;             /* toggle READ */
    printf("flags=%u\n", flags);
    return 0;
}

#include <stdio.h>
#include <limits.h>

int safe_add(int a, int b, int *out) {
    if (b > 0 && a > INT_MAX - b) return 0; /* would overflow */
    if (b < 0 && a < INT_MIN - b) return 0;
    *out = a + b;
    return 1;
}

int main(void) {
    unsigned u = UINT_MAX;
    printf("%u\n", u + 1u); /* defined: wraps to 0 */
    int r;
    printf("ok=%d\n", safe_add(INT_MAX, 1, &r));
    return 0;
}

