#include <stdio.h>

long factorial(int n) {
    if (n <= 1) return 1;      /* base case ends recursion */
    return n * factorial(n - 1); /* new stack frame per call */
}

int main(void) {
    void *vp = &(int){5};       /* generic pointer */
    int val = *(int*)vp;        /* cast before dereferencing */
    printf("%d! = %ld\n", val, factorial(val));
    return 0;
}
